    // ================= 2. ЧИТАННЯ З ФАЙЛУ =================
    ifstream inFile("players.txt");

    if (!inFile.is_open()) {
        cout << "Файл не знайдено!" << endl;
        return 1;
    }

    cout << "--- Вміст файлу ---" << endl;
    string line;
    // getline читає по одному РЯДКУ і повертає ПРАВДУ поки не кінець файлу (EOF)
    while (getline(inFile, line)) {
        cout << "Прочитано рядок: " << line << endl;
    }

    inFile.close(); // Не забуваємо закривати

    return 0;
